import sys

def count_similar_pairs(n, d, a):
    """Count the number of unordered position pairs with similar values."""
    count = 0
    for i in range(n):
        for j in range(i + 1, n):
            if abs(a[i] - a[j]) <= d:
                count += 1
    return count

def main():
    """Read input and print the result."""
    n, d = map(int, sys.stdin.readline().split())
    a = list(map(int, sys.stdin.readline().split()))
    result = count_similar_pairs(n, d, a)
    print(result)

if __name__ == "__main__":
    main()
